import { Component, h, Prop, Element, Event, EventEmitter, Listen } from '@stencil/core';

import { ButtonVariants, SurfaceVariant } from '../../components';
import { A11yAriaRole } from './wdpr-page-wide-message.model';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';

export type PageMessageVariant = 'success' | 'informational' | 'warning' | 'error';

@Component({
  tag: 'wdpr-page-wide-message',
  shadow: true,
})
export class WdprPageWideMessage {
  @Element() el: HTMLElement;

  @Prop() variant: PageMessageVariant = 'success';
  @Prop() titleMessage: string = '';
  @Prop() description?: string = '';
  @Prop() showDescription: boolean = false;
  @Prop() buttonText?: string = '';
  @Prop() showButton: boolean = false;

  @Prop({ attribute: 'a11y-aria-role' }) a11yAriaRole?: A11yAriaRole = 'status';
  @Prop({ attribute: 'a11y-button-label' }) a11yButtonLabel?: string;

  @Event() actionClicked!: EventEmitter<void>;

  @Listen('keydown')
  handleKeyDown(event: KeyboardEvent) {
    if (event.key == KEYBOARD_KEYS.ESCAPE) {
      event.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  private _handleClick = (event: Event) => {
    event?.stopPropagation?.();
    this.actionClicked.emit();
  };

  private _getCapitalValue(value: PageMessageVariant): string {
    return value.charAt(0).toUpperCase() + value.slice(1);
  }

  private get _mapVariant(): SurfaceVariant {
    const map: Record<PageMessageVariant, string> = {
      success: 'success-extra-bright-large',
      informational: 'informational-extra-bright-large',
      warning: 'warning-extra-bright-large',
      error: 'critical-dim-large',
    };

    return map[this.variant] as SurfaceVariant;
  }

  private get _ariaRole(): string | undefined {
    const value = (this?.a11yAriaRole || '').trim().toLowerCase();

    return value === 'alert' || value === 'status' ? value : undefined;
  }

  private get _buttonVariant(): ButtonVariants {
    return this.variant === 'error' ? 'tertiary-alt' : 'tertiary';
  }

  private get _containerClasses() {
    return `flex flex-wrap sm:flex-nowrap ${this.showDescription ? 'items-start' : 'items-center'} gap-150 w-full`;
  }

  private get _contentClasses() {
    return `min-w-0 flex flex-1 flex-wrap sm:flex-nowrap items-start gap-150 `;
  }

  private get _titleClasses() {
    return `line-clamp-1 heading-xsmall-alt ${this.variant === 'error' ? 'text-text-inverse' : 'text-text-heading'}`;
  }

  private get _descriptionClasses() {
    return `body-small line-clamp-4 ${this.variant === 'error' ? 'text-text-inverse' : 'text-text-body'}`;
  }

  render() {
    return (
      <wdpr-surface-style class={this._containerClasses} role={this._ariaRole} padding="md" variant={this._mapVariant}>
        <div class={this._contentClasses}>
          <div class="shrink-0">
            <wdpr-status-icon variant={this.variant} size="xxsmall" ariaLabel={this._getCapitalValue(this.variant)} />
          </div>

          <div class="flex-1 items-start flex flex-col gap-050 min-w-0 pt-025">
            <h2
              part="title"
              class={this._titleClasses}
              title={this.titleMessage || undefined}
            >
              {this.titleMessage}
            </h2>

            {this.showDescription && (
              <p
                part="description"
                class={this._descriptionClasses}
                title={this.description || undefined}
              >
                {this.description}
              </p>
            )}
          </div>

          {this.showButton && (
            <div class="shrink-0 w-full sm:w-auto">
              <slot name="action">
                <wdpr-button variant={this._buttonVariant} onClick={this._handleClick} a11yLabel={this.a11yButtonLabel ?? this.buttonText} display="block">
                  {this.buttonText}
                </wdpr-button>
              </slot>
            </div>
          )}
        </div>
      </wdpr-surface-style>
    );
  }
}
